import { useState, useRef, useEffect } from "react";

const LOGO_B64 = "";
const LOGO_SRC = `data:image/jpeg;base64,${LOGO_B64}`;

// ── Time phase
function getTimePhase() {
  const h=new Date().getHours(),m=new Date().getMinutes(),t=h*60+m;
  if(t>=7*60&&t<17*60) return "day";
  if(t>=17*60&&t<19*60) return "sunset";
  if(t>=19*60) return "night";
  if(t<5*60+30) return "midnight";
  return "dawn";
}

function getBg(phase){
  return {
    day:"radial-gradient(ellipse at 50% 0%,#87ceeb,#4a9fd4 40%,#1a6090)",
    sunset:"radial-gradient(ellipse at 60% 30%,#ff8c42,#c0392b 30%,#8e2090 60%,#1a0830)",
    night:"radial-gradient(ellipse at 50% 0%,#0a0420,#060210 60%,#020108)",
    midnight:"radial-gradient(ellipse at 50% 0%,#020108,#010106)",
    dawn:"radial-gradient(ellipse at 40% 70%,#ff9060,#c06040 20%,#604080 50%,#0a0420)",
  }[phase]||"#020810";
}

function TimeBackground({phase}){
  const [stars]=useState(()=>Array.from({length:55},()=>({x:Math.random()*100,y:Math.random()*60,s:Math.random()*2+.5,d:Math.random()*3})));
  const showS=phase==="night"||phase==="midnight";
  const showF=phase==="sunset";
  const isDk=phase==="night"||phase==="midnight"||phase==="sunset"||phase==="dawn";
  return(
    <div style={{position:"fixed",inset:0,zIndex:0,transition:"background 3s ease",background:getBg(phase)}}>
      {showS&&stars.map((s,i)=><div key={i} style={{position:"absolute",left:`${s.x}%`,top:`${s.y}%`,width:s.s,height:s.s,borderRadius:"50%",background:"white",animation:`twinkle ${1.5+s.d}s ease-in-out infinite`,animationDelay:`${s.d}s`,opacity:.85}}/>)}
      {showF&&stars.slice(0,18).map((s,i)=><div key={i} style={{position:"absolute",left:`${s.x}%`,top:`${s.y*.4}%`,width:s.s*.7,height:s.s*.7,borderRadius:"50%",background:"white",opacity:.35,animation:`twinkle ${2+s.d}s ease-in-out infinite`}}/>)}
      {(phase==="night"||phase==="midnight")&&(
        <div style={{position:"absolute",top:"8%",right:"12%",width:44,height:44,borderRadius:"50%",background:"radial-gradient(circle at 35% 35%,#fffde0,#d4c880)",boxShadow:"0 0 20px rgba(255,240,100,.4),0 0 50px rgba(255,240,100,.15)"}}>
          <div style={{position:"absolute",top:8,left:18,width:10,height:10,borderRadius:"50%",background:"rgba(180,160,60,.3)"}}/>
        </div>
      )}
      {phase==="day"&&<div style={{position:"absolute",top:"6%",right:"10%",width:52,height:52,borderRadius:"50%",background:"radial-gradient(circle,#fffde0,#ffd020 60%,#ff8c00)",boxShadow:"0 0 30px rgba(255,200,0,.6)"}}/>}
      {phase==="sunset"&&<div style={{position:"absolute",bottom:"18%",left:"50%",transform:"translateX(-50%)",width:60,height:60,borderRadius:"50%",background:"radial-gradient(circle,#fff0a0,#ff8c00 60%,#c04000)",boxShadow:"0 0 40px rgba(255,140,0,.8)"}}/>}
      {phase==="dawn"&&<div style={{position:"absolute",bottom:"12%",left:"30%",width:48,height:48,borderRadius:"50%",background:"radial-gradient(circle,#fffde0,#ffb040 60%,#ff6020)",boxShadow:"0 0 30px rgba(255,160,60,.7)"}}/>}
      {(phase==="day"||phase==="dawn")&&<>
        <div style={{position:"absolute",top:"15%",left:"5%",width:80,height:28,background:"rgba(255,255,255,.7)",borderRadius:20,filter:"blur(6px)"}}/>
        <div style={{position:"absolute",top:"22%",left:"60%",width:60,height:22,background:"rgba(255,255,255,.6)",borderRadius:20,filter:"blur(5px)"}}/>
      </>}
      <div style={{position:"absolute",bottom:0,left:0,right:0,height:"35%",background:isDk?"linear-gradient(to top,rgba(2,1,8,.9),transparent)":"linear-gradient(to top,rgba(10,30,10,.5),transparent)"}}/>
    </div>
  );
}

